var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"큭크크, 이 쬐끄만 녀석들. 어디에 숨어있는 것이냐?","JPN":"くっくっくっ、チビどもめ。どこに隠れておる？","ENG":"Heh heh heh. You little things. Where are you hiding?","TWN":"哼哼，你們這些小東西，都給我躲到哪裡去了？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"잡히면 모조리 씹어 먹어주겠노라.","JPN":"捕まえたら容赦なくかぶりついてやる。","ENG":"If I catch you, I'll chomp down on you.","TWN":"被我抓到的話，我就把你們通通吞下肚！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오, 찾았다!","JPN":"おお、見つけたぞ！","ENG":"Ooo, found you!","TWN":"喔喔！找到了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으끄응…! 팔이 안 닿아! 조금만 더…!","JPN":"うんぐぐ……手が届かない！　もう少し……！","ENG":"*Groan...* I can't reach... Just a little farther...","TWN":"唔呃…！我的手不夠長！要再伸長一點…！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…우앗!","JPN":"……うわっ！","ENG":"Wah!","TWN":"…哎呀！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이게 무슨 소리죠?","JPN":"これはどういうことですか？","ENG":"What's this noise?","TWN":"這是什麼聲音？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐익!","JPN":"ひいっ！","ENG":"Heek!","TWN":"嗚嗚！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기에 대체 왜 컵이 깨져 있는 건가요?","JPN":"なぜここでグラスが割れているのですか？","ENG":"Why is this glass broken?","TWN":"這裡怎麼會有打破的杯子？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그건… 저 손님이 꼭 이 컵으로 마셔야 한다고 해서…","JPN":"そ、それは……あのお客さんが絶対にこのグラスで飲みたいって言うから……","ENG":"Th-that's... because that customer insisted he would use this glass...","TWN":"那個…那個客人就說一定要用這個杯子喝酒…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"GUEST_VOICE_DRUNK_NULL","text":{"KOREA":"…으응? 나? 내가 그런 말을 했었던가?","JPN":"……うん？　俺？　俺そんなこと言ったっけ？","ENG":"Mm? Me? Did I say that?","TWN":"…喔？我嗎？我有說過這種話喔？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뻔하네요. 또 숨겨둔 사탕 찾느라 온 찬장을 다 헤집고 다닌 거죠?","JPN":"聞くまでもないですね。\\nまた隠しておいたキャンディーを探して食器棚を漁っていたんですね？","ENG":"You're so transparent. You rummaged through the cupboard again, looking for hidden candy, didn't you?","TWN":"我用膝蓋想也知道，你是不是翻箱倒櫃地想找藏起來的糖果？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"게다가 다른 사람에게 책임을 덮어 씌우다뇨! 오늘 하루동안 단 거 전부 금지예요!","JPN":"しかも他の人に責任をなすりつけるなんて！\\n今日一日甘いものは禁止です！","ENG":"You also put the blame on someone else. You're banned from sweets today!","TWN":"竟然還想責任賴到客人頭上！罰你今天都不能再吃糖果！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐에엑!","JPN":"ほええっ！","ENG":"Heek!","TWN":"嗚嗚嗚！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무, 무엄하다! 마왕인 이 몸을 통제하려 들다니!","JPN":"ぶ、無礼者！　魔王である吾輩の行動を制御しようとするなんて！","ENG":"H-how dare you? I'm a Demon Lord! You subject can't control me!","TWN":"大膽！竟然想控制本王！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"들어온 지 고작 일주일밖에 안 된 신입 하수인 주제에!","JPN":"入ってからたった一週間しか経っていない新人下僕のくせに！","ENG":"You've only been here for a week!","TWN":"你這個新人手下，進來不過才一個禮拜而已欸！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"신입이지만 매일 일도 안하고 먹을 것만 찾는 모모보단 가게에 보탬이 되고 있다고요.","JPN":"新人ですが、毎日仕事もせずに食べ物ばかり漁るモモよりは\\nお店に役立っていますよ。","ENG":"Be that as it may, but at least I work. And you, you just spend all day looking for food.","TWN":"我是新人沒錯，但我對這家店的貢獻比你大吧！你整天不做事，只知道找糖吃！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};